+        let mut state = RetryState::new(policy);
+
+        state.next_attempt(None); // attempt 1
+        state.next_attempt(None); // attempt 2
+
+        let error = state.into_error("failed");
+        assert_eq!(error.final_error, "failed");
+        assert_eq!(error.attempts, 2);
+    }
